{"action":"write","content":"const express = require('express');
const cors = require('cors');
const si = require('systeminformation');
const path = require('path');

const app = express();
const PORT = 3000;

// Middleware
app.use(cors());
app.use(express.static(path.join(__dirname, 'public')));

// API endpoint to get system metrics
app.get('/api/metrics', async (req, res) => {
    try {
        const [cpu, cpuLoad, mem, osInfo, time] = await Promise.all([
            si.cpu(),
            si.currentLoad(),
            si.mem(),
            si.osInfo(),
            si.time()
        ]);

        const metrics = {
            cpu: {
                manufacturer: cpu.manufacturer,
                brand: cpu.brand,
                cores: cpu.cores,
                physicalCores: cpu.physicalCores,
                speed: cpu.speed,
                currentLoad: Math.round(cpuLoad.currentLoad * 10) / 10
            },
            memory: {
                total: mem.total,
                used: mem.used,
                free: mem.free,
                available: mem.available,
                usedPercent: Math.round((mem.used / mem.total) * 1000) / 10
            },
            system: {
                hostname: osInfo.hostname,
                platform: osInfo.platform,
                distro: osInfo.distro,
                arch: osInfo.arch,
                uptime: time.uptime
            },
            timestamp: new Date().toISOString()
        };

        res.json(metrics);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Serve the dashboard
app.get('/', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

app.listen(PORT, () => {
    console.log(`Server running at http://localhost:${PORT}`);
    console.log('Dashboard: http://localhost:' + PORT);
});
","path":"server.js"}

