{"action":"write","content":"<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>System Monitor</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
            min-height: 100vh;
            color: #fff;
            padding: 20px;
        }

        .container {
            max-width: 1200px;
            margin: 0 auto;
        }

        h1 {
            text-align: center;
            margin-bottom: 10px;
            font-size: 2.5rem;
            background: linear-gradient(90deg, #00d9ff, #00ff88);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
        }

        .system-info {
            text-align: center;
            margin-bottom: 30px;
            color: #8892b0;
            font-size: 0.9rem;
        }

        .dashboard {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(350px, 1fr));
            gap: 20px;
        }

        .card {
            background: rgba(255, 255, 255, 0.05);
            border-radius: 16px;
            padding: 25px;
            backdrop-filter: blur(10px);
            border: 1px solid rgba(255, 255, 255, 0.1);
            transition: transform 0.3s ease, box-shadow 0.3s ease;
        }

        .card:hover {
            transform: translateY(-5px);
            box-shadow: 0 10px 40px rgba(0, 217, 255, 0.1);
        }

        .card-header {
            display: flex;
            align-items: center;
            margin-bottom: 20px;
        }

        .card-icon {
            width: 50px;
            height: 50px;
            border-radius: 12px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 1.5rem;
            margin-right: 15px;
        }

        .cpu-icon {
            background: linear-gradient(135deg, #667eea, #764ba2);
        }

        .memory-icon {
            background: linear-gradient(135deg, #f093fb, #f5576c);
        }

        .card-title {
            font-size: 1.3rem;
            font-weight: 600;
        }

        .card-subtitle {
            font-size: 0.85rem;
            color: #8892b0;
            margin-top: 2px;
        }

        .percentage {
            font-size: 3.5rem;
            font-weight: 700;
            margin-bottom: 10px;
        }

        .cpu-percentage {
            background: linear-gradient(90deg, #667eea, #764ba2);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
        }

        .memory-percentage {
            background: linear-gradient(90deg, #f093fb, #f5576c);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
        }

        .progress-bar {
            height: 12px;
            background: rgba(255, 255, 255, 0.1);
            border-radius: 6px;
            overflow: hidden;
            margin-bottom: 15px;
        }

        .progress-fill {
            height: 100%;
            border-radius: 6px;
            transition: width 0.5s ease;
        }

        .cpu-progress {
            background: linear-gradient(90deg, #667eea, #764ba2);
        }

        .memory-progress {
            background: linear-gradient(90deg, #f093fb, #f5576c);
        }

        .stats {
            display: flex;
            justify-content: space-between;
        }

        .stat {
            text-align: center;
        }

        .stat-value {
            font-size: 1.2rem;
            font-weight: 600;
            color: #00d9ff;
        }

        .stat-label {
            font-size: 0.75rem;
            color: #8892b0;
            margin-top: 4px;
        }

        .timestamp {
            text-align: center;
            margin-top: 30px;
            color: #8892b0;
            font-size: 0.85rem;
        }

        @keyframes pulse {
            0%, 100% { opacity: 1; }
            50% { opacity: 0.5; }
        }

        .loading {
            animation: pulse 1.5s infinite;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>System Monitor</h1>
        <div class="system-info" id="systemInfo">
            Loading system information...
        </div>

        <div class="dashboard">
            <div class="card">
                <div class="card-header">
                    <div class="card-icon cpu-icon">💻</div>
                    <div>
                        <div class="card-title">CPU Usage</div>
                        <div class="card-subtitle" id="cpuBrand">Loading...</div>
                    </div>
                </div>
                <div class="percentage cpu-percentage" id="cpuPercent">0%</div>
                <div class="progress-bar">
                    <div class="progress-fill cpu-progress" id="cpuBar" style="width: 0%"></div>
                </div>
                <div class="stats">
                    <div class="stat">
                        <div class="stat-value" id="cpuCores">-</div>
                        <div class="stat-label">Cores</div>
                    </div>
                    <div class="stat">
                        <div class="stat-value" id="cpuSpeed">-</div>
                        <div class="stat-label">Speed (GHz)</div>
                    </div>
                    <div class="stat">
                        <div class="stat-value" id="cpuLoad">-</div>
                        <div class="stat-label">Load Avg</div>
                    </div>
                </div>
            </div>

            <div class="card">
                <div class="card-header">
                    <div class="card-icon memory-icon">🧠</div>
                    <div>
                        <div class="card-title">Memory Usage</div>
                        <div class="card-subtitle" id="memoryTotal">Loading...</div>
                    </div>
                </div>
                <div class="percentage memory-percentage" id="memoryPercent">0%</div>
                <div class="progress-bar">
                    <div class="progress-fill memory-progress" id="memoryBar" style="width: 0%"></div>
                </div>
                <div class="stats">
                    <div class="stat">
                        <div class="stat-value" id="memoryUsed">-</div>
                        <div class="stat-label">Used</div>
                    </div>
                    <div class="stat">
                        <div class="stat-value" id="memoryFree">-</div>
                        <div class="stat-label">Free</div>
                    </div>
                    <div class="stat">
                        <div class="stat-value" id="memoryAvailable">-</div>
                        <div class="stat-label">Available</div>
                    </div>
                </div>
            </div>
        </div>

        <div class="timestamp">
            Last updated: <span id="lastUpdate">-</span>
        </div>
    </div>

    <script>
        function formatBytes(bytes) {
            const gb = bytes / (1024 * 1024 * 1024);
            return gb.toFixed(1) + ' GB';
        }

        function formatUptime(seconds) {
            const days = Math.floor(seconds / 86400);
            const hours = Math.floor((seconds % 86400) / 3600);
            const minutes = Math.floor((seconds % 3600) / 60);
            if (days > 0) {
                return `${days}d ${hours}h ${minutes}m`;
            }
            return `${hours}h ${minutes}m`;
        }

        function updateUI(data) {
            // CPU
            document.getElementById('cpuBrand').textContent = data.cpu.brand;
            document.getElementById('cpuPercent').textContent = data.cpu.currentLoad + '%';
            document.getElementById('cpuBar').style.width = data.cpu.currentLoad + '%';
            document.getElementById('cpuCores').textContent = data.cpu.physicalCores + '/' + data.cpu.cores;
            document.getElementById('cpuSpeed').textContent = data.cpu.speed;

            // Memory
            document.getElementById('memoryTotal').textContent = 'Total: ' + formatBytes(data.memory.total);
            document.getElementById('memoryPercent').textContent = data.memory.usedPercent + '%';
            document.getElementById('memoryBar').style.width = data.memory.usedPercent + '%';
            document.getElementById('memoryUsed').textContent = formatBytes(data.memory.used);
            document.getElementById('memoryFree').textContent = formatBytes(data.memory.free);
            document.getElementById('memoryAvailable').textContent = formatBytes(data.memory.available);

            // System Info
            document.getElementById('systemInfo').textContent = 
                `${data.system.hostname} | ${data.system.distro} (${data.system.arch}) | Uptime: ${formatUptime(data.system.uptime)}`;

            // Timestamp
            const updateTime = new Date(data.timestamp);
            document.getElementById('lastUpdate').textContent = updateTime.toLocaleTimeString();
        }

        async function fetchMetrics() {
            try {
                const response = await fetch('/api/metrics');
                if (!response.ok) throw new Error('Failed to fetch metrics');
                const data = await response.json();
                updateUI(data);
            } catch (error) {
                console.error('Error fetching metrics:', error);
            }
        }

        // Initial fetch
        fetchMetrics();

        // Poll every second
        setInterval(fetchMetrics, 1000);
    </script>
</body>
</html>
","path":"public/index.html"}

